div.script:

(function() {
    const STORAGE_KEY = 'phantom_fv';
    const hasBypassed = localStorage.getItem(STORAGE_KEY);
    const origin = window.location.hostname || "This site";
    document.getElementById("origin-text").textContent = origin;

    async function launchApp() {
        document.getElementById('fv-cloak').style.display = 'none';
        const iframe = document.getElementById('main-frame');

        // Using jsDelivr for the secondary page to ensure it's not blocked
        const target = "https://cdn.jsdelivr.net/gh/TalonGames/Talon101@main/index2.html";

        try {
            const response = await fetch(target);
            let pageHTML = await response.text();

            // Injecting base href so relative assets in index2.html still load from the CDN
            const currentBase = "https://cdn.jsdelivr.net/gh/TalonGames/Talon101@main/";
            pageHTML = pageHTML.replace(/<head>/i, `<head><base href="${currentBase}">`);

            const idoc = iframe.contentWindow.document;
            idoc.open();
            idoc.write(pageHTML);
            idoc.close();
        } catch (e) {
            iframe.src = target;
        }

        setTimeout(() => {
            document.getElementById('loading-screen').classList.add('hidden');
        }, 500);
    }

    // Key listener for the 'C' bypass
    document.addEventListener('keydown', (e) => {
        if (e.key.toLowerCase() === 'c') {
            localStorage.setItem(STORAGE_KEY, 'true');
            launchApp();
        }
    });

    if (!hasBypassed) {
        document.getElementById('fv-cloak').style.display = 'block';
    } else {
        launchApp();
    }
})();
